      if (lookahead == 'n') ADVANCE(120);
      END_STATE();
    case 119:
      if (lookahead == 'n') ADVANCE(121);
      END_STATE();
    case 120:
      if (lookahead == 'l') ADVANCE(122);
      END_STATE();
    case 121:
